import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as d,c as o,f as c}from"./app-e7c604ce.js";const a={},i=c('<h3 id="是什么" tabindex="-1"><a class="header-anchor" href="#是什么" aria-hidden="true">#</a> 是什么？</h3><ol><li>Calude Code 是由 Anthropic 开发的官方 CLI 工具，用于协助用户处理软件工程任务。 Anthropic 发现了Cursor的成功后，开发了Claude Code作为Cursor的竞品。</li><li>Claude是完全通过终端进行交互的，其中内置了多种工具，比如文件操作、搜索等。可以理解自然语言并转化为相应的命令执行。</li></ol><h3 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h3><h4 id="kimi-k2api-key获取" tabindex="-1"><a class="header-anchor" href="#kimi-k2api-key获取" aria-hidden="true">#</a> Kimi K2API key获取</h4><ol><li>Kimi K2新模型遵循Anthropic协议，这代表着其可以顺利接入Claude Code，并且无需任何路由代理，只需要配置好URL与API即可直接使用。</li><li>直接来到Moonshot官网获取自己的<code>API key</code>，注册后新建<code>API key</code>，然后将Moonshot的url以及<code>API key</code>设置进环境变量的系统变量中。<code>ANTHROPIC_API_KEY：API key</code> <code>ANTHROPIC_BASE_URL：https://api.moonshot.cn/anthropic/</code></li></ol><h4 id="claude-code-的安装" tabindex="-1"><a class="header-anchor" href="#claude-code-的安装" aria-hidden="true">#</a> Claude Code 的安装</h4><ol><li>安装Git，安装之后，配置环境变量<code>CLAUDE_CODE_GIT_BASH_PATH：git路径</code></li><li>安装Node.js 18+ 版本</li><li>安装claude-code : <code>npm install -g @anthropic-ai/claude-code</code> <code>claude --version</code></li><li>启动网络代理服务,在开启代理服务后还需要让cmd也能使用代理服务。</li><li>登陆方式，一种是官方的，一种使用Anthropic控制平台。选择第二种，会自动从环境变量中寻找配置信息登陆进去</li></ol><h3 id="claude-code-入门" tabindex="-1"><a class="header-anchor" href="#claude-code-入门" aria-hidden="true">#</a> Claude Code 入门</h3><ol><li>启动Claude Code:在项目根目录启动<code>claude</code>/<code>claude &quot;帮我分析这个项目的结构&quot;</code></li><li>语言设置:创建文件夹<code>.claude</code>，在.claude文件夹中创建文件<code>config.json</code></li><li>通过自然语言生成项目分析报告:读取工作目录下一个项目文件，并生成一份项目分析报告。比如输入<code>将C:\\Users\\Administrator\\Desktop\\test1\\drools_demo这个地址设置为你的工作目录,然后在此目录下生成一个分模块详细分析的项目说明文档</code>，它就会分析，经过一段然后时间后生出报告分析。</li><li>从零开始创建简单项目,<code>/add-dir &lt;工作目录&gt;</code>, 然后<code>输入指令:在此工作目录下创建一个使用JavaScript编写的简单的计时器程序，要求交互界面，可以一键运行</code>。输入后开始执行,在一段等待时间之后，其完成了该任务，创建了一个前端页面</li></ol><h3 id="claude-code-使用" tabindex="-1"><a class="header-anchor" href="#claude-code-使用" aria-hidden="true">#</a> Claude Code 使用</h3><p>Claude Code的斜杠命令配合自然语言输入，可以贯穿开发全流程：从环境准备、到编码调试、再到功能完善，以及最后的性能分析和优化，每一步都有相应的操作支持。灵活地组合运用命令和自然语言输入，能把重复繁杂的操作交给AI处理，开发者则专注于高层逻辑，实现真正的人机协作高效编程。<br> 场景：接手一个新项目，需要先熟悉代码，再开发新功能，最后提交PR并做审查。</p><ol><li>初始化项目记忆：进入项目目录，启动 Claude Code 后，首先运行 /init 创建 <code>CLAUDE.md</code> 项目指南。这样Claude对项目有基本认识。接着询问 <code>&quot;&gt; summarize this project&quot;</code>，Claude很快给出代码库概览，得益于刚生成的记忆文件提供的上下文。</li><li>配置模型与权限：发现默认模型对架构问题思考稍显吃力，于是输入 <code>/model opus</code> 切换到更强大的模型，以更好理解复杂代码结构。</li><li>编写代码与反馈：在Claude的协助下，开始编写新功能代码。Claude 直接在终端提议修改文件并执行了编辑。过程中会话变长，适时使用 <code>/compact &quot;保留新功能相关讨论&quot;</code> 将上下文压缩，让Claude聚焦当前任务。当一个模块修改完成，用 <code>/clear</code> 清理对话历史，针对下一个模块重新开始，确保Claude不被上一部分内容干扰。</li><li>代码功能完善</li><li>代码性能分析和优化</li></ol>',12),l=[i];function r(t,u){return d(),o("div",null,l)}const s=e(a,[["render",r],["__file","Claude code快速上手.html.vue"]]);export{s as default};
